SELECT CASE WHEN TBH.SHIPVOYAGE_ID IS NOT NULL THEN TBH.SHIP_NAME || '_' || TBH.VOYAGE END "shipNameVoyage", CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_NAME ELSE TBH.CARGO_OWNER_NAME END CARGO_OWNER_NAME, CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_ID ELSE TBH.CARGO_OWNER_ID END CARGO_OWNER_ID, CASE WHEN TBH.ID IS NULL THEN DECODE (TBCI.PACKING_NAME,'件', 1,'散' ,2,0) ELSE MC.WORK_TYPE END WORK_TYPE, CASE WHEN TBH.ID IS NULL THEN DECODE (TBCI.PACKING_NAME,'件', '件杂','散' ,'散杂','') ELSE DECODE(MC.WORK_TYPE, '1', '件杂', '2', '散杂', '3', '木材', NULL) end "workTypeLabel", CASE WHEN TBH.ID IS NULL THEN CASE WHEN MC.SIGN IS NOT NULL THEN TBCI.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBCI.CARGO_NAME END ELSE CASE WHEN MC.SIGN IS NOT NULL THEN TBH.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBH.CARGO_NAME END END AS CARGO_NAME, CASE WHEN TBH.ID IS NULL THEN TBCI.TRADE_TYPE ELSE TBH.TRADE_TYPE END TRADE_TYPE, CASE WHEN TBH.ID IS NULL THEN TDSI.LOAD_UNLOAD ELSE TBH.LOAD_UNLOAD END LOAD_UNLOAD, DECODE(TBCI.IS_CLEAR,'0','否','1','是','否') IS_CLEAR, TBH.ID, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TDS.SCN, TBH.SHIPVOYAGE_ID, TBH.SHIPVOYAGE_ITEM_ID, TBH.TRUST_ID, TBT.TRUST_NO, TBCI.ID "cargoInfoId", TBH.CARGO_CODE, TDS.BERTH_TIME, TDS.LEAVE_BERTH_TIME, TDS.LEAVE_PORT_TIME, TBT.RELEASE_TIME, DECODE(TCSS.ID, NULL, '-1', DECODE(TCSS.STATUS, '10', '1', TCS.STATUS)) "statementStatus", DECODE(TCSS.ID, NULL, '未结算', DECODE(TCSS.STATUS, '10', '已结算', DECODE(TCS.STATUS, '30', '计费审核', DECODE(TCS.STATUS, '31', '商务确认', DECODE(TCS.STATUS, '40', '部分开票', DECODE(TCS.STATUS, '50', '已开票', '')))))) "statementStatusLabel", TDSI.IMP_EXP, DECODE(TDSI.IMP_EXP, 'IN', '进口', '出口') "impExpLabel", TDSI.WORK_END_TIME, CASE WHEN ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '卸' THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - TDS.BERTH_TIME ELSE ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '装' THEN NVL(TDSI.WORK_END_TIME, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT ELSE ( CASE WHEN TBH.TYPE = '2' THEN NVL2(TBCI.CLEAR_DATE, TEMP3.MAX_WEIGH_OUT_DT, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END ) END ) END > CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE MAX(TEMP4.FREE_STORAGE_DAYS) END ) THEN '1' ELSE ( CASE WHEN ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '卸' THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - TDS.BERTH_TIME ELSE ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '装' THEN NVL(TDSI.WORK_END_TIME, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT ELSE ( CASE WHEN TBH.TYPE = '2' THEN NVL2(TBCI.CLEAR_DATE, TEMP3.MAX_WEIGH_OUT_DT, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END ) END ) END <= CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE MAX(TEMP4.FREE_STORAGE_DAYS) END ) THEN '0' ELSE NULL END ) END "isOverdue", CASE WHEN TBH.STATEMENT_STATUS_CODE = '30' THEN '1' ELSE '0' END IS_FINAL, CASE WHEN TBH.STATEMENT_STATUS_CODE = '30' THEN '是' ELSE '否' END IS_FINAL_LABEL, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, SUM(TCSS.AMOUNT) "amount" FROM
T_BUS_TRUST TBT LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBTC.TRUST_ID = TBT.ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN (SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST WHERE CHARGE_STATUS != '30' UNION SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST_TRANSFER WHERE CHARGE_STATUS != '30') TBH ON (TBH.TRUST_ID = TBT.ID AND TBH.CARGO_INFO_ID = TBCI.ID)
LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP5 ON TBCI.ID = TEMP5.CARGO_INFO_ID LEFT JOIN M_CARGO MC ON TBCI.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBH.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_COST_STORAGE_SETTLE TCSS ON TBH.ID = TCSS.HANDOVERLIST_ID LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCSS.ID = TCSD.BUSINESS_ID LEFT JOIN T_COST_STATEMENT TCS ON TCSD.STATEMENT = TCS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBH.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN( TEMP.WEIGH_OUT_DT ) MIN_WEIGH_OUT_DT, MAX( TEMP.WEIGH_OUT_DT ) MAX_WEIGH_OUT_DT FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE = '疏港' ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER( VWI2.CARGO_INFO_ID ), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE = '疏港' ) TEMP GROUP BY TEMP.CARGO_INFO_ID ) TEMP ON TBCI.ID = TEMP.CARGO_INFO_ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN( TEMP.WEIGH_OUT_DT ) MIN_WEIGH_OUT_DT, MAX( TEMP.WEIGH_OUT_DT ) MAX_WEIGH_OUT_DT FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港') ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER( VWI2.CARGO_INFO_ID ), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港') ) TEMP GROUP BY TEMP.CARGO_INFO_ID ) TEMP2 ON TBCI.ID = TEMP2.CARGO_INFO_ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN( TEMP.WEIGH_OUT_DT ) MIN_WEIGH_OUT_DT, MAX( TEMP.WEIGH_OUT_DT ) MAX_WEIGH_OUT_DT FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE = '陆销' ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER( VWI2.CARGO_INFO_ID ), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE = '陆销' ) TEMP GROUP BY TEMP.CARGO_INFO_ID ) TEMP3 ON TBCI.ID = TEMP3.CARGO_INFO_ID LEFT JOIN ( SELECT TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS FROM T_BUS_CONTRACT_COMPANY TBCC JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID) JOIN T_BUS_CONTRACT_RATE TBCR ON ( TBCR.RATE_ITEM_CODE = 'MS00240' AND TBC.ID = TBCR.CONTRACT_ID) GROUP BY TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS ) TEMP4 ON ( TBCI.COMPANY_ID = TEMP4.COMPANY_ID AND TBH.CARGO_OWNER_ID = TEMP4.CUSTOMER_ID AND CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE TEMP5.WEIGH_OUT_DT END >= TEMP4.START_TIME AND CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE TEMP5.WEIGH_OUT_DT END <= TEMP4.END_TIME AND TBH.CARGO_CODE = TEMP4.CARGO_CODE )
(SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST WHERE CHARGE_STATUS != '30' UNION SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST_TRANSFER WHERE CHARGE_STATUS != '30') TBH LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBH.CARGO_INFO_ID = TBCI.ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) WEIGH_OUT_DT FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) TEMP5 ON TBCI.ID = TEMP5.CARGO_INFO_ID LEFT JOIN M_CARGO MC ON TBH.CARGO_CODE = MC.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBH.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_BUS_TRUST TBT ON TBH.TRUST_ID = TBT.ID LEFT JOIN T_COST_STORAGE_SETTLE TCSS ON TBH.ID = TCSS.HANDOVERLIST_ID LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCSS.ID = TCSD.BUSINESS_ID LEFT JOIN T_COST_STATEMENT TCS ON TCSD.STATEMENT = TCS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBH.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN( TEMP.WEIGH_OUT_DT ) MIN_WEIGH_OUT_DT, MAX( TEMP.WEIGH_OUT_DT ) MAX_WEIGH_OUT_DT FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE = '疏港' ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER( VWI2.CARGO_INFO_ID ), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE = '疏港' ) TEMP GROUP BY TEMP.CARGO_INFO_ID ) TEMP ON TBCI.ID = TEMP.CARGO_INFO_ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN( TEMP.WEIGH_OUT_DT ) MIN_WEIGH_OUT_DT, MAX( TEMP.WEIGH_OUT_DT ) MAX_WEIGH_OUT_DT FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港') ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER( VWI2.CARGO_INFO_ID ), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港') ) TEMP GROUP BY TEMP.CARGO_INFO_ID ) TEMP2 ON TBCI.ID = TEMP2.CARGO_INFO_ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN( TEMP.WEIGH_OUT_DT ) MIN_WEIGH_OUT_DT, MAX( TEMP.WEIGH_OUT_DT ) MAX_WEIGH_OUT_DT FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE = '陆销' ) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER( VWI2.CARGO_INFO_ID ), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE = '陆销' ) TEMP GROUP BY TEMP.CARGO_INFO_ID ) TEMP3 ON TBCI.ID = TEMP3.CARGO_INFO_ID LEFT JOIN ( SELECT TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS FROM T_BUS_CONTRACT_COMPANY TBCC JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID) JOIN T_BUS_CONTRACT_RATE TBCR ON ( TBCR.RATE_ITEM_CODE = 'MS00240' AND TBC.ID = TBCR.CONTRACT_ID) GROUP BY TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS ) TEMP4 ON ( TBCI.COMPANY_ID = TEMP4.COMPANY_ID AND TBH.CARGO_OWNER_ID = TEMP4.CUSTOMER_ID AND CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE TEMP5.WEIGH_OUT_DT END >= TEMP4.START_TIME AND CASE WHEN TBH.LOAD_UNLOAD = '卸' THEN TDS.BERTH_TIME ELSE TEMP5.WEIGH_OUT_DT END <= TEMP4.END_TIME AND TBH.CARGO_CODE = TEMP4.CARGO_CODE )
TBT.STATUS NOT IN ('10', '20') AND TBT.TRUST_TYPE = '2' AND TBT.TYPE = '陆销'
TBH.TYPE = #{type,jdbcType=VARCHAR}
AND TBH.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TBH.SHIP_NAME LIKE #{shipName_like}
AND TBH.VOYAGE LIKE #{voyage_like}
AND MC.WORK_TYPE = #{workType}
AND TBH.CARGO_OWNER_ID = #{cargoOwnerId,jdbcType=BIGINT}
AND TDS.SHIP_STATUS_CODE = #{shipStatusCode,jdbcType=BIGINT}
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
AND TCSS.ID IS NULL
AND TCSS.STATUS = '10'
AND TCS.STATUS = #{statementStatus,jdbcType=VARCHAR}
AND TDS.LEAVE_BERTH_TIME >= #{beginLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_BERTH_TIME <= #{endLeaveBerthTime,jdbcType=TIMESTAMP}
AND TBH.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND CASE WHEN ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '卸' THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - TDS.BERTH_TIME ELSE ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '装' THEN NVL(TDSI.WORK_END_TIME, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT ELSE ( CASE WHEN TBH.TYPE = '2' THEN NVL2(TBCI.CLEAR_DATE, TEMP3.MAX_WEIGH_OUT_DT, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END ) END ) END > CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE TEMP4.FREE_STORAGE_DAYS END ) THEN '1' ELSE ( CASE WHEN ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '卸' THEN NVL2(TBCI.CLEAR_DATE, TEMP.MAX_WEIGH_OUT_DT, SYSDATE) - TDS.BERTH_TIME ELSE ( CASE WHEN TBH.TYPE = '1' AND TBH.LOAD_UNLOAD = '装' THEN NVL(TDSI.WORK_END_TIME, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT ELSE ( CASE WHEN TBH.TYPE = '2' THEN NVL2(TBCI.CLEAR_DATE, TEMP3.MAX_WEIGH_OUT_DT, SYSDATE) - TEMP2.MIN_WEIGH_OUT_DT END ) END ) END <= CASE WHEN TBCI.ROOT_ID IS NOT NULL THEN TBCI.RESIDUE_STORAGE ELSE TEMP4.FREE_STORAGE_DAYS END ) THEN '0' ELSE NULL END ) END = #{isOverdue,jdbcType=VARCHAR}
AND CASE WHEN TBH.STATEMENT_STATUS_CODE = '30' THEN '1' ELSE '0' END = #{isFinal,jdbcType=VARCHAR}
AND TBH.CARGO_CODE LIKE #{cargoCodeLike,jdbcType=VARCHAR}
AND TDSI.IMP_EXP = #{impExp,jdbcType=VARCHAR}
AND TDS.SCN LIKE #{scnLike,jdbcType=VARCHAR}
AND TBCI.CONTRACT_CODE LIKE #{contractCodeLike,jdbcType=VARCHAR}
GROUP BY TBCI.IS_CLEAR, CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_NAME ELSE TBH.CARGO_OWNER_NAME END, CASE WHEN TBH.ID IS NULL THEN TBCI.CARGO_OWNER_ID ELSE TBH.CARGO_OWNER_ID END, CASE WHEN TBH.ID IS NULL THEN DECODE (TBCI.PACKING_NAME,'件', 1,'散' ,2,0) ELSE MC.WORK_TYPE END, CASE WHEN TBH.ID IS NULL THEN DECODE (TBCI.PACKING_NAME,'件', '件杂','散' ,'散杂','') ELSE DECODE(MC.WORK_TYPE, '1', '件杂', '2', '散杂', '3', '木材', NULL) end, CASE WHEN TBH.ID IS NULL THEN CASE WHEN MC.SIGN IS NOT NULL THEN TBCI.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBCI.CARGO_NAME END ELSE CASE WHEN MC.SIGN IS NOT NULL THEN TBH.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBH.CARGO_NAME END END , CASE WHEN TBH.ID IS NULL THEN TBCI.TRADE_TYPE ELSE TBH.TRADE_TYPE END, CASE WHEN TBH.ID IS NULL THEN TDSI.LOAD_UNLOAD ELSE TBH.LOAD_UNLOAD END , TBH.ID, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TDS.SCN, TBH.SHIPVOYAGE_ID, TBH.SHIPVOYAGE_ITEM_ID, TBH.SHIP_NAME, TBH.VOYAGE, TBH.TRUST_ID, TBT.TRUST_NO, TBH.CARGO_OWNER_ID, TBH.CARGO_OWNER_NAME, TBCI.ID, MC.WORK_TYPE, TBH.CARGO_CODE, TBH.CARGO_NAME, TBH.TRADE_TYPE, TDS.BERTH_TIME, TDS.LEAVE_BERTH_TIME, TDS.LEAVE_PORT_TIME, TBT.RELEASE_TIME, TBH.LOAD_UNLOAD, TCSS.ID, TCSS.STATUS, TCS.STATUS, TDSI.IMP_EXP, TDSI.WORK_END_TIME, TBH.CREATE_TIME, TBH.TYPE, TEMP.MIN_WEIGH_OUT_DT, TEMP.MAX_WEIGH_OUT_DT, TEMP2.MIN_WEIGH_OUT_DT, TEMP2.MAX_WEIGH_OUT_DT, TEMP3.MIN_WEIGH_OUT_DT, TEMP3.MAX_WEIGH_OUT_DT, TBCI.ROOT_ID, TBCI.RESIDUE_STORAGE, TBH.STATEMENT_STATUS_CODE, TBH.STATEMENT_STATUS_NAME, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBH.CREATE_TIME
HAVING SUM(TCSS.AMOUNT) = 0
HAVING SUM(TCSS.AMOUNT) !=0
ORDER BY TDS.LEAVE_BERTH_TIME DESC

SELECT TCSSD.ID, TCSSD.STORAGE_SETTLE_ID, TCSSD."DATE", TCSSD.TON, TCSSD.BILLABLE_TON, TCSSD.IN_TON, TCSSD.OUT_TON, TCSSD.AMOUNT, TCSSD.TAX_AMOUNT FROM T_COST_STORAGE_SETTLE_DETAIL TCSSD JOIN T_COST_STORAGE_SETTLE TCSS ON TCSSD.STORAGE_SETTLE_ID = TCSS.ID WHERE TCSS.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
AND TCSSD."DATE" >= #{startDate,jdbcType=TIMESTAMP}
AND TCSSD."DATE" <= #{endDate,jdbcType=TIMESTAMP}

