UPDATE T_COST_STORAGE_SETTLE
SET STATUS         = #{status,jdbcType=VARCHAR},
    REVIEW_BY      = #{loginUserId,jdbcType=BIGINT},
    REVIEW_BY_NAME = #{loginUserName,jdbcType=BIGINT},
    REVIEW_BY_TIME = #{now,jdbcType=BIGINT}
WHERE ID = #{id,jdbcType=BIGINT}

UPDATE T_COST_STATEMENT SET STATUS = #{status, jdbcType=VARCHAR}
, STATEMENT_BY = #{statementBy,jdbcType=BIGINT}, STATEMENT_BY_NAME = #{statementByName,jdbcType=VARCHAR}, STATEMENT_TIME = #{statementTime,jdbcType=TIMESTAMP}
