SELECT TBH.ID, tbci.company_name, TBH.TYPE, TBH.CARGO_INFO_ID, TBH.TRUST_ID, TBH.TRUST_CARGO_ID, TBH.SHIPVOYAGE_ID, TBH.SHIPVOYAGE_ITEM_ID, TBH.SHIP_NAME, TBH.TRADE_TYPE, TBH.LOAD_UNLOAD, TBH.CARGO_OWNER_ID, TBH.CARGO_OWNER_NAME, TBH.CARGO_AGENT_ID, TBH.CARGO_AGENT_NAME, TBH.CARGO_CODE, TBH.CARGO_NAME, TBH.QUANTITY, TBH.TON, TBH.TICKET_NUM, TBH.STATEMENT_STATUS_CODE, TBH.STATEMENT_STATUS_NAME, TBH.REMARK, TBH.CREATE_BY, TBH.CREATE_BY_NAME, TBH.CREATE_TIME, TBH.UPDATE_BY, TBH.UPDATE_BY_NAME, TBH.UPDATE_TIME, TBH.VOYAGE, TBH.CONTRACT_ITEM_ID, TBH.CONTRACT_CODE, TBH.PRE_WEIGHT, TBH.VOLUME_TON, tds.ship_name || '_' || tdsd.voyage ship_Name_Voyage, b.TIN, b.BANK, b.BANK_ACCOUNT, b.TELEPHONE_NUMBER, b.CONTACT,b.ADDRESS, b.CONTACT_NUMBER FROM (SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST UNION SELECT ID, TYPE, CARGO_INFO_ID, TRUST_ID, TRUST_CARGO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SHIP_NAME, TRADE_TYPE, LOAD_UNLOAD, CARGO_OWNER_ID, CARGO_OWNER_NAME, CARGO_AGENT_ID, CARGO_AGENT_NAME, CARGO_CODE, CARGO_NAME, QUANTITY, TON, TICKET_NUM, STATEMENT_STATUS_CODE, STATEMENT_STATUS_NAME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, VOYAGE, CONTRACT_ITEM_ID, CONTRACT_CODE, PRE_WEIGHT, VOLUME_TON FROM T_BUS_HANDOVERLIST_TRANSFER) TBH LEFT JOIN T_BUS_CUSTOMER b ON TBH.CARGO_OWNER_ID = b.ID left join t_dis_shipvoyage tds on tds.id = TBH.shipvoyage_id left join t_dis_shipvoyage_item tdsd on tdsd.id = TBH.shipvoyage_item_id left join t_bus_cargo_info tbci on tbci.id = TBH.CARGO_INFO_ID
